const AWS = require('aws-sdk');
const s3 = new AWS.S3();

exports.handler = async (event) => {
    const bucketName = event.Records[0].s3.bucket.name;
    const key = decodeURIComponent(event.Records[0].s3.object.key.replace(/\+/g, ' '));
    
    try {
        // Read the file from S3
        const params = { Bucket: bucketName, Key: key };
        const data = await s3.getObject(params).promise();
        
        // Process the file (example: convert to uppercase)
        const processedData = data.Body.toString().toUpperCase();
        
        // Save results to another S3 location with the original filename
        const outputKey = `processed/${key}`;
        const outputParams = {
            Bucket: bucketName,
            Key: outputKey,
            Body: processedData,
            ContentType: 'text/plain'
        };
        await s3.putObject(outputParams).promise();
        
        return {
            statusCode: 200,
            body: JSON.stringify({ message: `File ${key} processed and saved as ${outputKey}` })
        };
    } catch (error) {
        console.error('Error processing file:', error);
        return {
            statusCode: 500,
            body: JSON.stringify({ message: 'Internal Server Error' })
        };
    }
};